import os
out_paths = [
    "images/headshot.jpg",
    "parallax-version/images/headshot.jpg",
]
base = os.path.dirname(os.path.abspath(__file__))
for rel in out_paths:
    full_path = os.path.join(base, rel)
    os.makedirs(os.path.dirname(full_path), exist_ok=True)
    with open(full_path, "wb") as f:
        f.write(data)
    print("wrote", full_path, os.path.getsize(full_path), "bytes")
